26	export function findTelegramTokenOwnerAccountId(params: {
27	  cfg: OpenClawConfig;
28	  accountId: string;
29	}): string | null {
30	  const normalizedAccountId = normalizeAccountId(params.accountId);
31	  const tokenOwners = new Map<string, string>();
32	  for (const id of listTelegramAccountIds(params.cfg)) {
33	    const account = inspectTelegramAccount({ cfg: params.cfg, accountId: id });
34	    const token = (account.token ?? "").trim();
35	    if (!token) {
36	      continue;
37	    }
38	    const ownerAccountId = tokenOwners.get(token);
39	    if (!ownerAccountId) {
40	      tokenOwners.set(token, account.accountId);
41	      continue;
42	    }
43	    if (account.accountId === normalizedAccountId) {
44	      return ownerAccountId;
45	    }
46	  }
47	  return null;
48	}
