46	function normalizeNostrAllowEntry(entry: string): string | "*" | null {
47	  const trimmed = entry.trim();
48	  if (!trimmed) {
49	    return null;
50	  }
51	  if (trimmed === "*") {
52	    return "*";
53	  }
54	  try {
55	    return normalizePubkey(trimmed.replace(/^nostr:/i, ""));
56	  } catch {
57	    return null;
58	  }
59	}
60	
61	function isNostrSenderAllowed(senderPubkey: string, allowFrom: string[]): boolean {
62	  const normalizedSender = normalizePubkey(senderPubkey);
63	  for (const entry of allowFrom) {
64	    const normalized = normalizeNostrAllowEntry(entry);
65	    if (normalized === "*") {
66	      return true;
67	    }
68	    if (normalized === normalizedSender) {
69	      return true;
70	    }
71	  }
72	  return false;
73	}
