#### **Nostr Structure (simplified overview)**

```typescript
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import {
  listNostrAccountIds,
  resolveDefaultNostrAccountId,
  resolveNostrAccount,
  type ResolvedNostrAccount,
} from "./types.js";
// ... other imports

export const nostrPlugin: ChannelPlugin<ResolvedNostrAccount> = createChatChannelPlugin({
  base: {
    id: "nostr",
    meta: {
      id: "nostr",
      label: "Nostr",
      selectionLabel: "Nostr",
      docsPath: "/channels/nostr",
      docsLabel: "nostr",
      blurb: "Decentralized DMs via Nostr relays (NIP-04)",
      order: 100,
    },
    capabilities: {
      chatTypes: ["direct"],  // DMs only for MVP
      media: false,           // No media for MVP
    },
    reload: { configPrefixes: ["channels.nostr"] },
    configSchema: buildChannelConfigSchema(NostrConfigSchema),
    setup: nostrSetupAdapter,
    setupWizard: nostrSetupWizard,
    config: {
      ...nostrConfigAdapter,
      isConfigured: (account) => account.configured,
      describeAccount: (account) =>
        describeAccountSnapshot({
          account,
          configured: account.configured,
          extra: {
            publicKey: account.publicKey,
          },
        }),
    },
    messaging: {
      normalizeTarget: (target) => {
        const cleaned = target.trim().replace(/^nostr:/i, "");
        try {
          return normalizePubkey(cleaned);
        } catch {
          return cleaned;
        }
      },
      targetResolver: {
        looksLikeId: (input) => {
          const trimmed = input.trim();
          return trimmed.startsWith("npub1") || /^[0-9a-fA-F]{64}$/.test(trimmed);
        },
        hint: "<npub|hex pubkey|nostr:npub...>",
      },
      resolveOutboundSessionRoute: (params) => resolveNostrOutboundSessionRoute(params),
    },
    status: {
      ...createComputedAccountStatusAdapter<ResolvedNostrAccount>({
        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
        collectStatusIssues: (accounts) => collectStatusIssuesFromLastError("nostr", accounts),
        buildChannelSummary: ({ snapshot }) =>
          buildPassiveChannelStatusSummary(snapshot, {
            publicKey: snapshot.publicKey ?? null,
          }),
        resolveAccountSnapshot: ({ account, runtime }) => ({
          accountId: account.accountId,
          name: account.name,
          enabled: account.enabled,
          configured: account.configured,
          extra: {
            publicKey: account.publicKey,
            profile: account.profile,
            ...buildTrafficStatusSummary(runtime),
          },
        }),
      }),
    },
    gateway: {
      startAccount: async (ctx) => {
        const account = ctx.account;
        ctx.setStatus({
          accountId: account.accountId,
          publicKey: account.publicKey,
        });

        if (!account.configured) {
          throw new Error("Nostr private key not configured");
        }

        const runtime = getNostrRuntime();
        const pairing = createChannelPairingController({
          core: runtime,
          channel: "nostr",
          accountId: account.accountId,
        });

        // Start Nostr bus and return cleanup
        const bus = await startNostrBus({
          accountId: account.accountId,
          privateKey: account.privateKey,
          relays: account.relays,
          authorizeSender: async ({ senderPubkey, reply }) => { ... },
          onMessage: async (senderPubkey, text, reply, meta) => { ... },
          onError: (error, context) => { ... },
          onConnect: (relay) => { ... },
          onDisconnect: (relay) => { ... },
          onEose: (relays) => { ... },
          onMetric: (event: MetricEvent) => { ... },
        });

        activeBuses.set(account.accountId, bus);

        return {
          stop: () => {
            bus.close();
            activeBuses.delete(account.accountId);
            metricsSnapshots.delete(account.accountId);
          },
        };
      },
    },
  },
  pairing: {
    text: {
      idLabel: "nostrPubkey",
      message: "Your pairing request has been approved!",
      normalizeAllowEntry: (entry) => {
        try {
          return normalizePubkey(entry.trim().replace(/^nostr:/i, ""));
        } catch {
          return entry.trim();
        }
      },
      notify: async ({ id, message }) => {
        const bus = activeBuses.get(DEFAULT_ACCOUNT_ID);
        if (bus) {
          await bus.sendDm(id, message);
        }
      },
    },
  },
  security: {
    resolveDmPolicy: resolveNostrDmPolicy,
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ cfg, to, text, accountId }) => {
      const core = getNostrRuntime();
      const aid = accountId ?? DEFAULT_ACCOUNT_ID;
      const bus = activeBuses.get(aid);
      if (!bus) {
        throw new Error(`Nostr bus not running for account ${aid}`);
      }
      const tableMode = core.channel.text.resolveMarkdownTableMode({
        cfg,
        channel: "nostr",
        accountId: aid,
      });
      const message = core.channel.text.convertMarkdownTables(text ?? "", tableMode);
      const normalizedTo = normalizePubkey(to);
      await bus.sendDm(normalizedTo, message);
      return attachChannelToResult("nostr", {
        to: normalizedTo,
        messageId: `nostr-${Date.now()}`,
      });
    },
  },
});
```

#### **createChatChannelPlugin() Structure**

The function signature accepts an object with these major sections:

```typescript
createChatChannelPlugin<Account, Probe>({
  base: {
    // Core plugin metadata and configuration
    id: string;
    meta: ChannelMeta;
    setup?: SetupAdapter<Account>;
    setupWizard?: SetupWizard<Account>;
    capabilities: {
      chatTypes: ("direct" | "group")[];
      media: boolean;
      blockStreaming?: boolean;
    };
    reload: { configPrefixes: string[] };
    configSchema: JsonSchema;
    config: ConfigAdapter<Account>;

    // Groups (for multi-user channels like IRC channels)
    groups?: {
      resolveRequireMention: (params) => boolean;
      resolveToolPolicy: (params) => GroupToolPolicyConfig | undefined;
    };

    // Message normalization and resolution
    messaging: {
      normalizeTarget: (target: string) => string;
      targetResolver: {
        looksLikeId: (input: string) => boolean;
        hint: string;
      };
      resolveOutboundSessionRoute?: (params) => any;
    };

    // Target resolution (for commands)
    resolver?: {
      resolveTargets: async (params) => ResolveResult[];
    };

    // Directory listing (peers and groups)
    directory?: ChannelDirectoryAdapter;

    // Status monitoring
    status: AccountStatusAdapter<Account, Probe>;

    // Gateway (startup/shutdown)
    gateway: {
      startAccount: async (ctx) => StopHandler;
    };
  };

  pairing: {
    text: {
      idLabel: string;
      message: string;
      normalizeAllowEntry: (entry: string) => string | null;
      notify: async (params) => void;
    };
  };

  security: {
    resolveDmPolicy: DmSecurityResolver<Account>;
    collectWarnings?: WarningCollector<Account>;
  };

  outbound: {
    base?: {
      deliveryMode: "direct" | "batched";
      chunker?: TextChunker;
      chunkerMode?: "markdown" | "plain";
      textChunkLimit?: number;
    };
    attachedResults?: {
      channel: string;
      sendText: async (params) => void;
      sendMedia: async (params) => void;
    } | {
      deliveryMode: "direct";
      textChunkLimit: number;
      sendText: async (params) => SendResult;
    };
  };
})
```

