397	      };
398	    }
399	  | {
400	      resolveReplyToMode: NonNullable<ChannelThreadingAdapter["resolveReplyToMode"]>;
401	    };
402	
403	type ChatChannelThreadingOptions<TResolvedAccount> =
404	  ChatChannelThreadingReplyModeOptions<TResolvedAccount> &
405	    Omit<ChannelThreadingAdapter, "resolveReplyToMode">;
406	
407	type ChatChannelAttachedOutboundOptions = {
408	  base: Omit<ChannelOutboundAdapter, "sendText" | "sendMedia" | "sendPoll">;
409	  attachedResults: {
410	    channel: string;
411	    sendText?: (
412	      ctx: Parameters<NonNullable<ChannelOutboundAdapter["sendText"]>>[0],
413	    ) => MaybePromise<Omit<OutboundDeliveryResult, "channel">>;
414	    sendMedia?: (
415	      ctx: Parameters<NonNullable<ChannelOutboundAdapter["sendMedia"]>>[0],
416	    ) => MaybePromise<Omit<OutboundDeliveryResult, "channel">>;
417	    sendPoll?: (
418	      ctx: Parameters<NonNullable<ChannelOutboundAdapter["sendPoll"]>>[0],
419	    ) => MaybePromise<Omit<ChannelPollResult, "channel">>;
420	  };
421	};
422	
423	type MaybePromise<T> = T | Promise<T>;
424	
425	function createInlineAttachedChannelResultAdapter(
426	  params: ChatChannelAttachedOutboundOptions["attachedResults"],
427	) {
428	  return {
429	    sendText: params.sendText
430	      ? async (ctx: Parameters<NonNullable<ChannelOutboundAdapter["sendText"]>>[0]) => ({
431	          channel: params.channel,
432	          ...(await params.sendText!(ctx)),
433	        })
434	      : undefined,
435	    sendMedia: params.sendMedia
436	      ? async (ctx: Parameters<NonNullable<ChannelOutboundAdapter["sendMedia"]>>[0]) => ({
437	          channel: params.channel,
438	          ...(await params.sendMedia!(ctx)),
439	        })
440	      : undefined,
441	    sendPoll: params.sendPoll
442	      ? async (ctx: Parameters<NonNullable<ChannelOutboundAdapter["sendPoll"]>>[0]) => ({
443	          channel: params.channel,
444	          ...(await params.sendPoll!(ctx)),
445	        })
446	      : undefined,
447	  } satisfies Pick<ChannelOutboundAdapter, "sendText" | "sendMedia" | "sendPoll">;
448	}
449	
450	function resolveChatChannelSecurity<TResolvedAccount extends { accountId?: string | null }>(
451	  security:
452	    | ChannelSecurityAdapter<TResolvedAccount>
453	    | ChatChannelSecurityOptions<TResolvedAccount>
454	    | undefined,
455	): ChannelSecurityAdapter<TResolvedAccount> | undefined {
456	  if (!security) {
457	    return undefined;
458	  }
459	  if (!("dm" in security)) {
460	    return security;
461	  }
462	  return {
463	    resolveDmPolicy: ({ cfg, accountId, account }) =>
464	      buildAccountScopedDmSecurityPolicy({
465	        cfg,
466	        channelKey: security.dm.channelKey,
467	        accountId,
468	        fallbackAccountId: security.dm.resolveFallbackAccountId?.(account) ?? account.accountId,
469	        policy: security.dm.resolvePolicy(account),
470	        allowFrom: security.dm.resolveAllowFrom(account) ?? [],
471	        defaultPolicy: security.dm.defaultPolicy,
472	        allowFromPathSuffix: security.dm.allowFromPathSuffix,
473	        policyPathSuffix: security.dm.policyPathSuffix,
474	        approveChannelId: security.dm.approveChannelId,
475	        approveHint: security.dm.approveHint,
476	        normalizeEntry: security.dm.normalizeEntry,
477	      }),
478	    ...(security.collectWarnings ? { collectWarnings: security.collectWarnings } : {}),
479	  };
480	}
481	
482	function resolveChatChannelPairing(
483	  pairing: ChannelPairingAdapter | ChatChannelPairingOptions | undefined,
484	): ChannelPairingAdapter | undefined {
485	  if (!pairing) {
486	    return undefined;
487	  }
488	  if (!("text" in pairing)) {
489	    return pairing;
490	  }
491	  return createInlineTextPairingAdapter(pairing.text);
492	}
493	
494	function resolveChatChannelThreading<TResolvedAccount>(
495	  threading: ChannelThreadingAdapter | ChatChannelThreadingOptions<TResolvedAccount> | undefined,
496	): ChannelThreadingAdapter | undefined {
497	  if (!threading) {
498	    return undefined;
499	  }
500	  if (!("topLevelReplyToMode" in threading) && !("scopedAccountReplyToMode" in threading)) {
501	    return threading;
502	  }
503	
504	  let resolveReplyToMode: ChannelThreadingAdapter["resolveReplyToMode"];
505	  if ("topLevelReplyToMode" in threading) {
506	    resolveReplyToMode = createTopLevelChannelReplyToModeResolver(threading.topLevelReplyToMode);
507	  } else {
508	    resolveReplyToMode = createScopedAccountReplyToModeResolver<TResolvedAccount>(
509	      threading.scopedAccountReplyToMode,
510	    );
511	  }
512	
513	  return {
514	    ...threading,
515	    resolveReplyToMode,
516	  };
517	}
518	
519	function resolveChatChannelOutbound(
520	  outbound: ChannelOutboundAdapter | ChatChannelAttachedOutboundOptions | undefined,
521	): ChannelOutboundAdapter | undefined {
522	  if (!outbound) {
523	    return undefined;
524	  }
525	  if (!("attachedResults" in outbound)) {
526	    return outbound;
527	  }
528	  return {
529	    ...outbound.base,
530	    ...createInlineAttachedChannelResultAdapter(outbound.attachedResults),
531	  };
532	}
