import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import { createChatChannelPlugin, getChatChannelMeta } from "openclaw/plugin-sdk/core";
import { getPulseBoardRuntime } from "./runtime.js";

// Minimal resolved account shape satisfying createChatChannelPlugin's generic constraint
type ResolvedPulseBoardAccount = {
  accountId: string | null;
};

export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      ...getChatChannelMeta("pulseboard" as Parameters<typeof getChatChannelMeta>[0]),
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin)",
      docsPath: "/channels/pulseboard",
      blurb: "Real-time bulletin board messaging with boards and DMs.",
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: () => ["default"],
      resolveAccount: () => ({ accountId: "default" }),
      defaultAccountId: () => "default",
      isConfigured: () => false,
    },
    setup: {
      applyAccountConfig: ({ cfg }) => cfg,
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(
          `[${ctx.account.accountId ?? "default"}] PulseBoard provider connected`,
        );
      },
    },
    messaging: {
      normalizeTarget: (target) => target.trim(),
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to }) => {
      return attachChannelToResult("pulseboard", {
        to,
        messageId: `pb-${Date.now()}`,
      });
    },
  },
});

